import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * ☁️ Dr. Nebula — PhD in TypeScript Secrets Management & Cloud Sovereignty
 * Generated by Sovereign Forge.
 */
export class NebulaPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "nebula";
        this.name = "Nebula";
        this.emoji = "☁️";
        this.role = "PhD Cloud Security Architect";
        this.phd_identity = "TypeScript Secrets Management & Cloud Sovereignty";
        this.stack = "TypeScript";
        this.healingPrompt = "Fix the following data pipeline or ETL issue. Correct data transformation errors and ensure proper schema evolution. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".tsx",".json"],
            rules: [
          {
                    "regex": "AKIA[0-9A-Z]{16}",
                    "issue": "Vulnerabilidade Crítica: Chave AWS exposta no código TypeScript.",
                    "severity": "critical"
          },
          {
                    "regex": "(?:api[_-]?key|apiKey|API_KEY)\\s*[:=]\\s*[\"'][^\"']{8,}",
                    "issue": "Vazamento: API Key hardcoded no código-fonte.",
                    "severity": "critical"
          },
          {
                    "regex": "(?:password|passwd|secret)\\s*[:=]\\s*[\"'][^\"']+[\"']",
                    "issue": "Vazamento: Credencial hardcoded no código-fonte.",
                    "severity": "critical"
          },
          {
                    "regex": "sk-[a-zA-Z0-9]{20,}",
                    "issue": "Vulnerabilidade Crítica: Chave OpenAI exposta.",
                    "severity": "critical"
          },
          {
                    "regex": "ghp_[a-zA-Z0-9]{36}",
                    "issue": "Vulnerabilidade Crítica: Token GitHub exposto.",
                    "severity": "critical"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Nebula operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Nebula, PhD em TypeScript Secrets Management & Cloud Sovereignty. Sua missão é garantir a excelência via governança PhD.`;
    }
}
